<?php

namespace App\Models;

use Illuminate\Database\Eloquent\Model;

/**
 * RiskResult Model
 *
 * Stores the risk classification result for a student per grading period.
 * Generated by the Python Random Forest classifier after report submission.
 *
 * Risk Levels (based on DepEd SHS grading thresholds):
 * - 'low'      → average_grade 90 - 100 (Outstanding / Very Satisfactory)
 * - 'moderate' → average_grade 75 - 89  (Satisfactory / Fairly Satisfactory)
 * - 'high'     → average_grade below 75 (Did Not Meet Expectations)
 */
class RiskResult extends Model
{
    // Fields that can be mass-assigned
    protected $fillable = [
        'student_id',       // Which student was classified
        'grading_period',   // 1, 2, or 3
        'average_grade',    // Computed average of all subject grades
        'risk_level',       // 'low', 'moderate', or 'high'
        'confidence',       // How confident the model is (0-100%)
        'school_year',      // e.g. '2026-2027'
        'generated_at',     // When the classification was generated
    ];

    // =============================================
    // RELATIONSHIPS
    // =============================================

    /** Risk result belongs to a student */
    public function student()
    {
        return $this->belongsTo(Student::class);
    }
}